import React, { useState } from 'react';
import type { LaunchProject } from '../types';

interface OpenSalesSectionProps {
    data: LaunchProject[];
    onProjectClick: (project: LaunchProject) => void;
    onViewAllClick: () => void;
}

export const OpenSalesSection: React.FC<OpenSalesSectionProps> = ({ data, onProjectClick, onViewAllClick }) => {
    const [isOpen, setIsOpen] = useState(true);

    if (data.length === 0) {
        return null; // Don't render the section if there's no data
    }

    const getSector = (location: string) => {
        const parts = location.split(',').map(p => p.trim());
        // Assumes the sector is the second to last part, which is robust for the current data format.
        if (parts.length >= 2) {
            return parts[parts.length - 2];
        }
        return parts[0];
    };

    const handleShareProject = async (project: LaunchProject) => {
        const shareText = `Confira este lançamento imobiliário:

*Empreendimento:* ${project.name}
*Construtora:* ${project.builder}
*Localização:* ${project.location}
*Status:* ${project.status}
*Entrega:* ${project.delivery}
*Tipologias:* ${project.typologies}
*Metragem:* ${project.size}
*Preço:* ${project.price}
*Descrição:* ${project.description}

Saiba mais!`;

        if (navigator.share) {
            try {
                await navigator.share({
                    title: `Lançamento: ${project.name}`,
                    text: shareText,
                    url: window.location.href, // Sharing the current app URL as a generic link
                });
            } catch (error) {
                console.error('Erro ao compartilhar:', error);
                if ((error as any).name !== 'AbortError') { // AbortError means user cancelled share, not an actual error
                    alert('Não foi possível compartilhar. Copiando para a área de transferência.');
                    await navigator.clipboard.writeText(shareText);
                }
            }
        } else {
            // Fallback for browsers that do not support navigator.share
            try {
                await navigator.clipboard.writeText(shareText);
                alert('Detalhes do projeto copiados para a área de transferência!');
            } catch (err) {
                console.error('Falha ao copiar para a área de transferência:', err);
                alert('Não foi possível compartilhar ou copiar os detalhes.');
            }
        }
