interface LaunchSectionProps {
    data: LaunchProject[];
    onProjectClick: (project: LaunchProject) => void;
    filterStatus: string;
    onFilterChange: (status: string) => void;
}

export const LaunchSection = forwardRef<HTMLElement, LaunchSectionProps>(({ data, onProjectClick, filterStatus, onFilterChange }, ref) => {
    const [isOpen, setIsOpen] = useState(true);
    const [currentPage, setCurrentPage] = useState(1);

    const uniqueStatuses = useMemo(() => {
        const statuses = new Set<string>();
        data.forEach(project => statuses.add(project.status));
        return ['Todos', ...Array.from(statuses).sort()];
    }, [data]);

    const filteredProjects = useMemo(() => {
        if (filterStatus === 'Todos') {
            return data;
        }
        return data.filter(project => project.status === filterStatus);
    }, [data, filterStatus]);

    useEffect(() => {
        setCurrentPage(1);
    }, [filterStatus]);

    const totalPages = Math.ceil(filteredProjects.length / LAUNCHES_PER_PAGE);
    const paginatedProjects = useMemo(() => {
        const startIndex = (currentPage - 1) * LAUNCHES_PER_PAGE;
        return filteredProjects.slice(startIndex, startIndex + LAUNCHES_PER_PAGE);
    }, [filteredProjects, currentPage]);

    const handleShareProject = async (project: LaunchProject) => {
        const shareText = `Confira este lançamento imobiliário:

*Empreendimento:* ${project.name}
*Construtora:* ${project.builder}
*Localização:* ${project.location}
*Status:* ${project.status}
*Entrega:* ${project.delivery}
*Tipologias:* ${project.typologies}
*Metragem:* ${project.size}
*Preço:* ${project.price}
*Descrição:* ${project.description}

Saiba mais!`;

        if (navigator.share) {
            try {
                await navigator.share({
                    title: `Lançamento: ${project.name}`,
                    text: shareText,
                    url: window.location.href,
                });
            } catch (error) {
                 if ((error as any).name !== 'AbortError') {
                    alert('Não foi possível compartilhar. Copiando para a área de transferência.');
                    await navigator.clipboard.writeText(shareText);
                }
            }
        } else {
            try {
                await navigator.clipboard.writeText(shareText);
                alert('Detalhes do projeto copiados para a área de transferência!');
            } catch (err) {
                console.error(err);
                alert('Não foi possível compartilhar ou copiar os detalhes.');
            }
        }
    };

    return (
        <section ref={ref} className="mb-16 transition-all duration-300">
            <div 
                className="flex items-center justify-center mb-8 cursor-pointer group select-none"
                onClick={() => setIsOpen(!isOpen)}
