import React, { useState, useMemo, useEffect } from 'react';
import type { Job } from '../types';

interface JobSectionProps {
    jobs: Job[];
}

const JtJobListItem: React.FC<{ job: Job }> = ({ job }) => {
    // Remove JT prefix (case-insensitive) and trim whitespace
    let formattedJt = job.jt.replace(/^JT\s*/i, '');

    // Replace GT with GY (case-insensitive)
    if (formattedJt.toUpperCase().startsWith('GT')) {
        formattedJt = 'GY' + formattedJt.substring(2);
    }

    // Format GY prefix with space if needed
    if (formattedJt.startsWith('GY') && !formattedJt.includes(' ')) {
        formattedJt = `GY ${formattedJt.substring(2)}`;
    }

    // Check if it's a special job (starts with GY or was GT)
    const isSpecialJob = job.jt.startsWith('GY') || job.jt.startsWith('GT');

    // Clean up agents for display
    const displayAgents = job.agents
        ? job.agents.map(agent => agent.replace(/^-+\s*|\s*-+$/g, '').trim()).filter(Boolean).join(', ')
        : '';

    return (
        <div 
            className={`
                group relative flex flex-col aspect-square p-5 rounded-2xl border transition-all duration-500 ease-out cursor-default overflow-hidden backdrop-blur-md shadow-sm
