    onViewAllClick: () => void;
}

export const OpenSalesSection: React.FC<OpenSalesSectionProps> = ({ data, onProjectClick, onViewAllClick }) => {
    const [isOpen, setIsOpen] = useState(true);

    if (data.length === 0) {
        return null; // Don't render the section if there's no data
    }

    const getSector = (location: string) => {
        const parts = location.split(',').map(p => p.trim());
        // Assumes the sector is the second to last part, which is robust for the current data format.
        if (parts.length >= 2) {
            return parts[parts.length - 2];
        }
        return parts[0];
    };

    const copyToClipboard = async (text: string) => {
        // Try the modern Clipboard API first
        if (navigator.clipboard && window.isSecureContext) {
            try {
                await navigator.clipboard.writeText(text);
                alert('Detalhes do projeto copiados para a área de transferência!');
                return;
            } catch (err) {
                console.warn('Clipboard API failed, trying fallback...', err);
            }
        }

        // Fallback method using execCommand
        try {
            const textArea = document.createElement("textarea");
            textArea.value = text;

            // Ensure the textarea is not visible but part of the DOM
            textArea.style.position = "fixed";
            textArea.style.left = "-9999px";
            textArea.style.top = "0";
            document.body.appendChild(textArea);

            textArea.focus();
            textArea.select();

            const successful = document.execCommand('copy');
            document.body.removeChild(textArea);

            if (successful) {
                alert('Detalhes do projeto copiados para a área de transferência!');
            } else {
                throw new Error('execCommand failed');
            }
        } catch (err) {
            console.error('Falha ao copiar:', err);
            alert('Não foi possível compartilhar ou copiar os detalhes. Por favor, tente selecionar e copiar manualmente.');
        }
    };

    const handleShareProject = async (project: LaunchProject) => {
        const shareText = `Confira este lançamento imobiliário:

*Empreendimento:* ${project.name}
*Construtora:* ${project.builder}
*Localização:* ${project.location}
*Status:* ${project.status}
*Entrega:* ${project.delivery}
*Tipologias:* ${project.typologies}
*Metragem:* ${project.size}
*Preço:* ${project.price}
*Descrição:* ${project.description}

Saiba mais!`;

        if (navigator.share) {
            try {
                await navigator.share({
                    title: `Lançamento: ${project.name}`,
                    text: shareText,
                    url: window.location.href,
                });
            } catch (error) {
                console.error('Erro ao compartilhar:', error);
                // Only try copy if it wasn't a user cancellation
                if ((error as any).name !== 'AbortError') { 
                    await copyToClipboard(shareText);
                }
            }
        } else {
            await copyToClipboard(shareText);
        }
    };

    return (
        <section className="mb-16 transition-all duration-300">
            <div 
                className="flex items-center justify-center mb-8 cursor-pointer group select-none"
